import React, { useState, useEffect, useCallback } from 'react';
import { ethers } from 'ethers';
import { AlertCircle, CheckCircle, ArrowRight, Loader } from 'lucide-react';
import { motion } from 'framer-motion';
import { P3D_PRECOMPILE_ADDRESS } from '../config/networks';

const Expatriation = ({ 
  bridgeInstance, 
  formData, 
  sourceToken, 
  signer, 
  onSuccess, 
  onError 
}) => {
  const [step, setStep] = useState('approve'); // 'approve', 'approved', 'transfer', 'success'
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [approvalTxHash, setApprovalTxHash] = useState('');
  const [transferTxHash, setTransferTxHash] = useState('');
  const [currentAllowance, setCurrentAllowance] = useState('0');
  const [requiredAmount, setRequiredAmount] = useState('0');
  const [requiredStake, setRequiredStake] = useState('0');
  const [totalRequired, setTotalRequired] = useState('0');
  const [tokenDecimals, setTokenDecimals] = useState(sourceToken.decimals || 18);
  const [stakeAllowance, setStakeAllowance] = useState('0');
  const [p3dDecimals, setP3dDecimals] = useState(18);
  const [isCheckingApproval, setIsCheckingApproval] = useState(true);

  // Create token contract for approval
  const createTokenContract = (tokenAddress) => {
    const tokenABI = [
      'function approve(address spender, uint256 amount) external returns (bool)',
      'function allowance(address owner, address spender) external view returns (uint256)',
      'function balanceOf(address account) external view returns (uint256)',
      'function decimals() external view returns (uint8)',
      'function symbol() external view returns (string)'
    ];
    return new ethers.Contract(tokenAddress, tokenABI, signer);
  };

  // Create export bridge contract
  const createExportContract = () => {
    const exportABI = [
      'function transferToForeignChain(string foreign_address, string data, uint amount, int reward) payable',
      'function foreign_network() view returns (string)',
      'function foreign_asset() view returns (string)',
      'function getRequiredStake(uint amount) view returns (uint)'
    ];
    return new ethers.Contract(bridgeInstance.address, exportABI, signer);
  };

  // Create P3D token contract (for stake approvals)
  const createP3DContract = () => {
    const tokenABI = [
      'function approve(address spender, uint256 amount) external returns (bool)',
      'function allowance(address owner, address spender) external view returns (uint256)',
      'function balanceOf(address account) external view returns (uint256)',
      'function decimals() external view returns (uint8)',
      'function symbol() external view returns (string)'
    ];
    return new ethers.Contract(P3D_PRECOMPILE_ADDRESS, tokenABI, signer);
  };

  // Check if approval is needed
  const checkApprovalNeeded = useCallback(async () => {
    try {
      setIsCheckingApproval(true);
      const tokenContract = createTokenContract(sourceToken.address);
      const actualDecimals = await tokenContract.decimals();
      setTokenDecimals(actualDecimals);
      const amount = ethers.utils.parseUnits(formData.amount, actualDecimals);
      const exportContract = createExportContract();
      const stake = await exportContract.getRequiredStake(amount); // Stake is in P3D units
      const p3dContract = createP3DContract();
      const p3dDec = await p3dContract.decimals();
      setP3dDecimals(p3dDec);
      const total = amount; // total allowance for source token is just the amount
      const owner = await signer.getAddress();
      const allowance = await tokenContract.allowance(owner, bridgeInstance.address);
      const stakeAll = await p3dContract.allowance(owner, bridgeInstance.address);

      // Store the values for display
      setRequiredAmount(ethers.utils.formatUnits(amount, actualDecimals));
      setRequiredStake(ethers.utils.formatUnits(stake, p3dDec));
      setTotalRequired(ethers.utils.formatUnits(total, actualDecimals));
      setCurrentAllowance(ethers.utils.formatUnits(allowance, actualDecimals));
      setStakeAllowance(ethers.utils.formatUnits(stakeAll, p3dDec));

      const needsApproval = allowance.lt(amount) || stakeAll.lt(stake);
      console.log('🔍 Approval check:', {
        requiredAmount: ethers.utils.formatUnits(amount, actualDecimals),
        requiredStake: ethers.utils.formatUnits(stake, p3dDec),
        amountAllowance: ethers.utils.formatUnits(allowance, actualDecimals),
        stakeAllowance: ethers.utils.formatUnits(stakeAll, p3dDec),
        needsApproval
      });

      return needsApproval;
    } catch (error) {
      console.error('Error checking approval:', error);
      setError('Failed to check approval status: ' + error.message);
      return true; // Assume approval is needed if check fails
    } finally {
      setIsCheckingApproval(false);
    }
  }, [sourceToken.address, sourceToken.decimals, formData.amount, bridgeInstance.address, signer]);

  // Handle approval
  const handleApprove = async () => {
    setIsLoading(true);
    setError('');

    try {
      console.log('🔍 Starting approval process...');
      console.log('📋 Approval details:', {
        tokenAddress: sourceToken.address,
        bridgeAddress: bridgeInstance.address,
        amount: formData.amount,
        decimals: sourceToken.decimals
      });

      const tokenContract = createTokenContract(sourceToken.address);
      const actualDecimals = await tokenContract.decimals();
      const amount = ethers.utils.parseUnits(formData.amount, actualDecimals);
      const exportContract = createExportContract();
      const stake = await exportContract.getRequiredStake(amount); // in P3D units
      const p3dContract = createP3DContract();
      const p3dDec = await p3dContract.decimals();

      console.log('💰 Parsed amount for approval:', ethers.utils.formatUnits(amount, actualDecimals));
      console.log('💰 Required P3D stake for approval:', ethers.utils.formatUnits(stake, p3dDec));

      // Check current allowance
      const owner = await signer.getAddress();
      const currentAllowance = await tokenContract.allowance(owner, bridgeInstance.address);
      const currentStakeAllowance = await p3dContract.allowance(owner, bridgeInstance.address);
      console.log('📊 Current token allowance:', ethers.utils.formatUnits(currentAllowance, actualDecimals));
      console.log('📊 Current P3D stake allowance:', ethers.utils.formatUnits(currentStakeAllowance, p3dDec));

      let approvedSomething = false;

      if (currentAllowance.lt(amount)) {
        console.log('🔐 Approving bridge to spend transfer token...');
        const approveTx = await tokenContract.approve(bridgeInstance.address, amount, { gasLimit: 100000 });
        console.log('⏳ Waiting for transfer token approval confirmation...');
        await approveTx.wait();
        setApprovalTxHash(approveTx.hash);
        approvedSomething = true;
      }

      if (currentStakeAllowance.lt(stake)) {
        console.log('🔐 Approving bridge to spend P3D for stake...');
        const approveStakeTx = await p3dContract.approve(bridgeInstance.address, stake, { gasLimit: 100000 });
        console.log('⏳ Waiting for P3D stake approval confirmation...');
        await approveStakeTx.wait();
        approvedSomething = true;
      }

      if (!approvedSomething) {
        console.log('✅ Sufficient allowance already exists');
        setStep('approved');
        setIsLoading(false);
        return;
      }
      console.log('✅ Approvals completed');
      setStep('approved');

    } catch (error) {
      console.error('❌ Approval failed:', error);
      setError(error.message || 'Approval failed');
    } finally {
      setIsLoading(false);
    }
  };

  // Handle transfer
  const handleTransfer = async () => {
    setIsLoading(true);
    setError('');

    try {
      console.log('🌉 Starting transfer process...');
      console.log('📋 Transfer details:', {
        bridgeAddress: bridgeInstance.address,
        foreignAddress: formData.destinationAddress,
        amount: formData.amount,
        reward: formData.reward,
        decimals: sourceToken.decimals
      });

      const exportContract = createExportContract();

      // Get actual token decimals from contract to avoid configuration mismatches
      const tokenContract = createTokenContract(sourceToken.address);
      const actualDecimals = await tokenContract.decimals();

      // Use actual decimals instead of configured ones
      const amount = ethers.utils.parseUnits(formData.amount, actualDecimals);
      const reward = ethers.utils.parseUnits(formData.reward, actualDecimals);
      // Ensure allowances still cover amount and stake right before transfer
      try {
        const stake = await exportContract.getRequiredStake(amount); // P3D units
        const owner = await signer.getAddress();
        const allowanceAmount = await tokenContract.allowance(owner, bridgeInstance.address);
        const p3dContract = createP3DContract();
        const allowanceStake = await p3dContract.allowance(owner, bridgeInstance.address);
        if (allowanceAmount.lt(amount)) throw new Error('Insufficient token allowance. Please approve again.');
        if (allowanceStake.lt(stake)) throw new Error('Insufficient P3D stake allowance. Please approve again.');
      } catch (stakeCheckError) {
        console.warn('⚠️ Stake re-check before transfer failed:', stakeCheckError);
        throw stakeCheckError;
      }
      const data = '0x'; // Empty data for ERC20 transfers (matching test script)

      console.log('💰 Parsed amounts:', {
        amount: ethers.utils.formatUnits(amount, actualDecimals),
        reward: ethers.utils.formatUnits(reward, actualDecimals)
      });

      // Validate parameters
      console.log('🔍 Transfer parameters:', {
        foreignAddress: formData.destinationAddress,
        data: data,
        amount: amount.toString(),
        reward: reward.toString(),
        amountType: typeof amount,
        rewardType: typeof reward
      });

      // Validate bridge contract configuration
      try {
        const foreignNetwork = await exportContract.foreign_network();
        const foreignAsset = await exportContract.foreign_asset();
        console.log('🔍 Bridge configuration:', {
          foreignNetwork,
          foreignAsset
        });
      } catch (error) {
        console.warn('⚠️ Could not verify bridge configuration:', error);
      }

      // Validate token configuration
      try {
        const tokenContract = createTokenContract(sourceToken.address);
        const tokenDecimals = await tokenContract.decimals();
        const tokenSymbol = await tokenContract.symbol();
        const tokenBalance = await tokenContract.balanceOf(await signer.getAddress());

        console.log('🔍 Token validation:', {
          address: sourceToken.address,
          configuredDecimals: sourceToken.decimals,
          actualDecimals: tokenDecimals,
          configuredSymbol: sourceToken.symbol,
          actualSymbol: tokenSymbol,
          balance: ethers.utils.formatUnits(tokenBalance, tokenDecimals),
          parsedAmount: ethers.utils.formatUnits(amount, tokenDecimals),
          hasEnoughBalance: tokenBalance.gte(amount)
        });

        // Check if decimals mismatch
        if (sourceToken.decimals !== tokenDecimals) {
          console.warn('⚠️ Token decimals mismatch!', {
            configured: sourceToken.decimals,
            actual: tokenDecimals
          });
        }
      } catch (error) {
        console.warn('⚠️ Could not validate token configuration:', error);
      }

      console.log('🌉 Initiating transfer to foreign chain...');
      // Preflight: simulate call to catch reverts early with readable message
      try {
        await exportContract.callStatic.transferToForeignChain(
          formData.destinationAddress,
          data,
          amount,
          reward
        );
      } catch (simError) {
        console.error('❌ Preflight transfer simulation failed:', simError);
        const nested = simError.error?.data || simError.data;
        // Try to decode a standard revert reason if present
        let detailed = simError.reason || simError.error?.message || simError.message;
        if (typeof nested === 'string' && nested.startsWith('0x08c379a0')) {
          try {
            const iface = new ethers.utils.Interface(['function Error(string)']);
            const decoded = iface.decodeFunctionData('Error', nested);
            detailed = decoded?.[0] || detailed;
          } catch (e) {}
        }
        throw new Error(detailed || 'Transfer would fail (simulation)');
      }

      const transferTx = await exportContract.transferToForeignChain(
        formData.destinationAddress,
        data,
        amount,
        reward,
        { gasLimit: 900000 }
      );

      console.log('⏳ Waiting for transfer transaction confirmation...');
      const receipt = await transferTx.wait();

      console.log('✅ Transfer transaction confirmed:', receipt.transactionHash);
      setTransferTxHash(receipt.transactionHash);
      setStep('success');

      // Call success callback
      if (onSuccess) {
        onSuccess(receipt.transactionHash);
      }

    } catch (error) {
      console.error('❌ Transfer failed:', error);
      setError(error.message || 'Transfer failed');
    } finally {
      setIsLoading(false);
    }
  };

  // Check if approval is needed on component mount
  useEffect(() => {
    const checkApproval = async () => {
      try {
        const needsApproval = await checkApprovalNeeded();
        if (!needsApproval) {
          setStep('approved');
        }
      } catch (error) {
        console.error('Error in approval check:', error);
        setError('Failed to check approval status');
      }
    };

    if (signer && sourceToken && bridgeInstance) {
      checkApproval();
    }
  }, [signer, sourceToken, bridgeInstance, checkApprovalNeeded]);

  const renderStep = () => {
    switch (step) {
      case 'approve':
        return (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="space-y-4"
          >
            <div className="bg-warning-900/50 border border-warning-700 rounded-lg p-4">
              <div className="flex items-start space-x-3">
                <AlertCircle className="w-5 h-5 text-warning-400 mt-0.5 flex-shrink-0" />
                <div className="flex-1">
                  <h3 className="text-warning-400 font-medium">Approval Required</h3>
                  <p className="text-warning-300 text-sm mt-1">
                    You need to approve the bridge contract to spend your {sourceToken.symbol} tokens before initiating the transfer.
                  </p>

                  {!isCheckingApproval && (
                    <div className="mt-3 space-y-2">
                      <div className="flex justify-between text-sm">
                        <span className="text-warning-300">Transfer amount:</span>
                        <span className="text-warning-400 font-medium">{requiredAmount} {sourceToken.symbol}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-warning-300">Required stake:</span>
                        <span className="text-warning-400 font-medium">{requiredStake} {sourceToken.symbol}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-warning-300">Total required allowance:</span>
                        <span className="text-warning-400 font-medium">{totalRequired} {sourceToken.symbol}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-warning-300">Current allowance:</span>
                        <span className="text-warning-400 font-medium">{currentAllowance} {sourceToken.symbol}</span>
                      </div>
                      {parseFloat(currentAllowance) > 0 && (
                        <div className="text-xs text-warning-300 mt-1">
                          You have an existing allowance, but it might be insufficient (needs amount + stake).
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <button
                onClick={handleApprove}
                disabled={isLoading || isCheckingApproval}
                className="w-full btn-warning py-3 text-lg font-medium disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isLoading ? (
                  <div className="flex items-center justify-center space-x-2">
                    <Loader className="w-5 h-5 animate-spin" />
                    <span>Approving...</span>
                  </div>
                ) : isCheckingApproval ? (
                  <div className="flex items-center justify-center space-x-2">
                    <Loader className="w-5 h-5 animate-spin" />
                    <span>Checking Approval Status...</span>
                  </div>
                ) : (
                  <div className="flex items-center justify-center space-x-2">
                    <span>Approve {sourceToken.symbol}</span>
                    <ArrowRight className="w-5 h-5" />
                  </div>
                )}
              </button>

              <button
                onClick={async () => {
                  setError('');
                  await checkApprovalNeeded();
                }}
                disabled={isCheckingApproval}
                className="w-full btn-secondary py-2 text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isCheckingApproval ? (
                  <div className="flex items-center justify-center space-x-2">
                    <Loader className="w-4 h-4 animate-spin" />
                    <span>Checking...</span>
                  </div>
                ) : (
                  <span>Refresh Approval Status</span>
                )}
              </button>
            </div>
          </motion.div>
        );

      case 'approved':
        return (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="space-y-4"
          >
            <div className="bg-success-900/50 border border-success-700 rounded-lg p-4">
              <div className="flex items-start space-x-3">
                <CheckCircle className="w-5 h-5 text-success-400 mt-0.5 flex-shrink-0" />
                <div className="flex-1">
                  <h3 className="text-success-400 font-medium">Approval Successful</h3>
                  <p className="text-success-300 text-sm mt-1">
                    Bridge contract is now approved to spend your {sourceToken.symbol} tokens.
                  </p>

                  <div className="mt-3 space-y-2">
                    <div className="flex justify-between text-sm">
                      <span className="text-success-300">Current allowance:</span>
                      <span className="text-success-400 font-medium">{currentAllowance} {sourceToken.symbol}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-success-300">Required amount:</span>
                      <span className="text-success-400 font-medium">{requiredAmount} {sourceToken.symbol}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-success-300">Required stake:</span>
                      <span className="text-success-400 font-medium">{requiredStake} {sourceToken.symbol}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-success-300">Total required allowance:</span>
                      <span className="text-success-400 font-medium">{totalRequired} {sourceToken.symbol}</span>
                    </div>
                  </div>

                  {approvalTxHash && (
                    <p className="text-success-300 text-xs mt-2 font-mono">
                      TX: {approvalTxHash.slice(0, 10)}...{approvalTxHash.slice(-8)}
                    </p>
                  )}
                </div>
              </div>
            </div>

            <button
              onClick={handleTransfer}
              disabled={isLoading}
              className="w-full btn-primary py-3 text-lg font-medium disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isLoading ? (
                <div className="flex items-center justify-center space-x-2">
                  <Loader className="w-5 h-5 animate-spin" />
                  <span>Initiating Transfer...</span>
                </div>
              ) : (
                <div className="flex items-center justify-center space-x-2">
                  <span>Initiate Transfer</span>
                  <ArrowRight className="w-5 h-5" />
                </div>
              )}
            </button>
          </motion.div>
        );

      case 'success':
        return (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-success-900/50 border border-success-700 rounded-lg p-4"
          >
            <div className="flex items-start space-x-3">
              <CheckCircle className="w-5 h-5 text-success-400 mt-0.5 flex-shrink-0" />
              <div>
                <h3 className="text-success-400 font-medium">Transfer Successful</h3>
                <p className="text-success-300 text-sm mt-1">
                  Your {sourceToken.symbol} tokens have been successfully transferred to {formData.destinationNetwork}.
                </p>
                {transferTxHash && (
                  <p className="text-success-300 text-xs mt-2 font-mono">
                    TX: {transferTxHash.slice(0, 10)}...{transferTxHash.slice(-8)}
                  </p>
                )}
              </div>
            </div>
          </motion.div>
        );

      default:
        return null;
    }
  };

  if (error) {
    return (
      <div className="bg-error-900/50 border border-error-700 rounded-lg p-4">
        <div className="flex items-start space-x-3">
          <AlertCircle className="w-5 h-5 text-error-400 mt-0.5 flex-shrink-0" />
          <div>
            <h3 className="text-error-400 font-medium">Operation Failed</h3>
            <p className="text-error-300 text-sm mt-1">{error}</p>
            <button
              onClick={() => {
                setError('');
                setStep('approve');
              }}
              className="text-error-400 text-sm mt-2 hover:text-error-300 underline"
            >
              Try Again
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {renderStep()}
    </div>
  );
};

export default Expatriation;
